// 用户个人资料服务
export interface UserProfileService {
  // 获取用户资料
  GetUser(
    request: wellKnownEmpty,
  ): Promise<identityservicev1_User>;
  // 更新用户资料
  UpdateUser(
    request: identityservicev1_UpdateUserRequest,
  ): Promise<wellKnownEmpty>;
  // 修改用户密码
  ChangePassword(
    request: identityservicev1_ChangePasswordRequest,
  ): Promise<wellKnownEmpty>;
  // 上传头像
  UploadAvatar(
    request: identityservicev1_UploadAvatarRequest,
  ): Promise<identityservicev1_UploadAvatarResponse>;
  // 删除头像
  DeleteAvatar(
    request: wellKnownEmpty,
  ): Promise<wellKnownEmpty>;
  // 绑定手机号码/邮箱
  BindContact(
    request: identityservicev1_BindContactRequest,
  ): Promise<wellKnownEmpty>;
  // 验证手机号码/邮箱
  VerifyContact(
    request: identityservicev1_VerifyContactRequest,
  ): Promise<wellKnownEmpty>;
}

export function createUserProfileServiceClient(
  transport: ClientTransport,
): UserProfileService {
  return {
    GetUser(_request) {
      const path = `admin/v1/me`;
      const body = null;
      return transport.unary(path, 'GET', body, {
        service: 'UserProfileService',
        method: 'GetUser',
      }) as Promise<identityservicev1_User>;
    },
    UpdateUser(request) {
      const path = `admin/v1/me`;
      const body = JSON.stringify(request);
      return transport.unary(path, 'PUT', body, {
        service: 'UserProfileService',
        method: 'UpdateUser',
      }) as Promise<wellKnownEmpty>;
    },
    ChangePassword(request) {
      const path = `admin/v1/me/password`;
      const body = JSON.stringify(request);
      return transport.unary(path, 'POST', body, {
        service: 'UserProfileService',
        method: 'ChangePassword',
      }) as Promise<wellKnownEmpty>;
    },
    UploadAvatar(request) {
      const path = `admin/v1/me/avatar`;
      const body = JSON.stringify(request);
      return transport.unary(path, 'POST', body, {
        service: 'UserProfileService',
        method: 'UploadAvatar',
      }) as Promise<identityservicev1_UploadAvatarResponse>;
    },
    DeleteAvatar(_request) {
      const path = `admin/v1/me/avatar`;
      const body = null;
      return transport.unary(path, 'DELETE', body, {
        service: 'UserProfileService',
        method: 'DeleteAvatar',
      }) as Promise<wellKnownEmpty>;
    },
    BindContact(request) {
      const path = `admin/v1/me/contact`;
      const body = JSON.stringify(request);
      return transport.unary(path, 'POST', body, {
        service: 'UserProfileService',
        method: 'BindContact',
      }) as Promise<wellKnownEmpty>;
    },
    VerifyContact(request) {
      const path = `admin/v1/me/contact/verify`;
      const body = JSON.stringify(request);
      return transport.unary(path, 'POST', body, {
        service: 'UserProfileService',
        method: 'VerifyContact',
      }) as Promise<wellKnownEmpty>;
    },
  };
}
// 修改用户密码（需要验证旧密码） - 请求
export type identityservicev1_ChangePasswordRequest = {
  newPassword: string | undefined;
  oldPassword: string | undefined;
};

export type identityservicev1_UploadAvatarRequest = {
  imageBase64?: string;
  imageUrl?: string;
};

export type identityservicev1_UploadAvatarResponse = {
  url: string | undefined;
};

export type identityservicev1_BindContactRequest = {
  email?: identityservicev1_BindEmailRequest;
  phone?: identityservicev1_BindPhoneRequest;
};

export type identityservicev1_BindPhoneRequest = {
  code: string | undefined;
  phone: string | undefined;
};

export type identityservicev1_BindEmailRequest = {
  email: string | undefined;
  verificationCode?: string;
};

export type identityservicev1_VerifyContactRequest = {
  email?: identityservicev1_EmailVerification;
  phone?: identityservicev1_PhoneVerification;
  // 可选：服务端生成的验证码会话 id（用于多步骤或回调验证）
  verificationId?: string;
};

// 手机验证
export type identityservicev1_PhoneVerification = {
  //
  // Behaviors: REQUIRED
  code: string | undefined;
  phone: string | undefined;
};

// 邮箱验证
export type identityservicev1_EmailVerification = {
  //
  // Behaviors: REQUIRED
  code: string | undefined;
  email: string | undefined;
};

